def unita_di_lavoro(metadato=None, tempo_limite=None):
    def decoratore(funzione):
        def wrapper(*args, **kwargs):
            transazione = args[0]  # La transazione è il primo argomento
            if metadato is not None:
                transazione.set_metadata(metadato)
            if tempo_limite is not None:
                transazione.set_timeout(tempo_limite)
            return funzione(*args, **kwargs)
        return wrapper
    return decoratore

def tipo_di_punto(nome, campi, srid_map):
    """
    Crea dinamicamente una sottoclasse di Point.

    :param nome: Nome della sottoclasse da creare.
    :param campi: Lista di campi aggiuntivi per la sottoclasse.
    :param srid_map: Dizionario che mappa i nomi dei campi ai loro SRID.
    :return: La sottoclasse creata.
    """
    from shapely.geometry import Point

    class PuntoPersonalizzato(Point):
        def __init__(self, *args, **kwargs):
            super().__init__(*args)
            for campo, valore in kwargs.items():
                setattr(self, campo, valore)

        def __repr__(self):
            attributi = {campo: getattr(self, campo) for campo in campi}
            return f"{nome}({super().__repr__()}, {attributi})"

    PuntoPersonalizzato.__name__ = nome
    PuntoPersonalizzato.__qualname__ = nome

    for campo in campi:
        setattr(PuntoPersonalizzato, campo, None)

    PuntoPersonalizzato.srid_map = srid_map

    return PuntoPersonalizzato

