def nomi_e_descrizioni(self, tutti=False): # pylint:disable=redefined-builtin
    """Restituisce i nomi e le descrizioni degli attributi definiti dall'interfaccia."""
    attributi = self.__dict__.items()
    risultato = {}

    for nome, valore in attributi:
        if not tutti and nome.startswith("_"):
            continue
        descrizione = valore.__doc__ if valore.__doc__ else "Nessuna descrizione disponibile"
        risultato[nome] = descrizione

    return risultato

def _normalizza_argomenti(sequenza, output=None):
    """
    Normalizza gli argomenti della dichiarazione

    Gli argomenti di normalizzazione possono contenere Dichiarazioni, tuple o singole
    interfacce.

    Qualsiasi cosa diversa da interfacce individuali o specifiche di implementazione verrà espansa.
    """
    if output is None:
        output = []

    for elemento in sequenza:
        if isinstance(elemento, (list, tuple)):
            _normalizza_argomenti(elemento, output)
        else:
            output.append(elemento)

    return output

def _ottieni_indici_errore(self, nome_coordinata):
    """
    Ottieni gli indici di errore corrispondenti a una coordinata.
    """
    indici_errore = []
    for indice, coordinata in enumerate(self.coordinate):
        if coordinata == nome_coordinata:
            indici_errore.append(indice)
    return indici_errore

import copy

def differenza(d1, d2, livello=-1):
    """
    Restituisce un dizionario con gli elementi di *d1* che non sono contenuti in *d2*.

    Il parametro *livello* definisce la profondità massima della ricorsione. Per una ricorsione infinita, impostare *livello* a -1. Per livello 1, se una chiave è presente sia in *d1* che in *d2* ma ha valori diversi, viene inclusa nella differenza. Consulta la funzione :func:`intersection` per ulteriori dettagli.

    *d1* e *d2* rimangono invariati. Tuttavia, *d1* o alcuni dei suoi sottodizionari potrebbero essere restituiti direttamente. Effettua una copia profonda (deep copy) del risultato quando appropriato.

    .. versione aggiunta:: 0.5
       Aggiunto il parametro *livello*.
    """
    risultato = {}

    for chiave, valore in d1.items():
        if chiave not in d2:
            risultato[chiave] = copy.deepcopy(valore)
        elif livello != 0 and isinstance(valore, dict) and isinstance(d2[chiave], dict):
            differenza_interna = differenza(valore, d2[chiave], livello - 1 if livello != -1 else -1)
            if differenza_interna:
                risultato[chiave] = differenza_interna
        elif valore != d2[chiave]:
            risultato[chiave] = copy.deepcopy(valore)

    return risultato

import re

class ValidationError(Exception):
    def __init__(self, messaggi):
        self.messaggi = messaggi
        super().__init__(str(messaggi))

def _valida_etichette(etichette):
    """
    Verifica che le chiavi e i valori nelle etichette fornite corrispondano alle rispettive espressioni regolari.

    ### Argomenti:
    - **etichette (dict)**: il dizionario contenente le diverse etichette da validare.

    ### Eccezioni:
    - **ValidationError**: viene sollevata se una qualsiasi delle chiavi o dei valori delle etichette non corrisponde alla rispettiva espressione regolare.
    """
    regex_chiave = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_]*$')
    regex_valore = re.compile(r'^[a-zA-Z0-9_]+$')

    errori = []

    for chiave, valore in etichette.items():
        if not isinstance(chiave, str):
            errori.append({str(chiave): 'La chiave deve essere una stringa'})
        elif not regex_chiave.match(chiave):
            errori.append({chiave: f"La chiave '{chiave}' non corrisponde al formato richiesto"})

        if not isinstance(valore, str):
            errori.append({str(valore): 'Il valore deve essere una stringa'})
        elif not regex_valore.match(valore):
            errori.append({valore: f"Il valore '{valore}' non corrisponde al formato richiesto"})

    if errori:
        raise ValidationError(errori)

def formatta(
        self,
        sql: AnyStr,
        parametri: Union[Dict[Union[str, int], Any], Sequence[Any]],
) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:
    """
    Converte la query SQL per utilizzare i parametri in stile "out" invece dei parametri in stile "in".

    **sql** (:class:`str` o :class:`bytes`) è la query SQL.

    Restituisce una :class:`tuple` contenente:

    - La query SQL formattata (:class:`str` o :class:`bytes`).

    - L'insieme dei parametri convertiti in stile "out" (:class:`dict` o :class:`list`).
    """
    if isinstance(parametri, dict):
        parametri_out = {}
        for chiave, valore in parametri.items():
            parametri_out[f"out_{chiave}"] = valore
        sql_formattato = sql.replace("?", ":out_")
    elif isinstance(parametri, (list, tuple)):
        parametri_out = [f"out_{i}" for i in range(len(parametri))]
        sql_formattato = sql.replace("?", ":out_")
    else:
        raise TypeError("I parametri devono essere un dizionario o una sequenza")

    return sql_formattato, parametri_out

def ottieni_mappa_percorsi_logici(inventario, versione):
    """
    Ottiene una mappa dei percorsi logici nello stato verso i file su disco per una determinata versione nell'inventario.

    Restituisce un dizionario: `logical_path_in_state -> set(content_files)`

    Il set di `content_files` può includere riferimenti a file duplicati presenti in versioni successive rispetto alla versione descritta.
    """
    mappa_percorsi = {}

    for percorso_logico, contenuti in inventario.items():
        file_corrispondenti = set()
        for file_contenuto in contenuti:
            if file_contenuto["versione"] <= versione:
                file_corrispondenti.add(file_contenuto["file"])
        if file_corrispondenti:
            mappa_percorsi[percorso_logico] = file_corrispondenti

    return mappa_percorsi

def assorbimento(self, argomenti):
    """
    Dato un insieme `argomenti` di espressioni, restituisce una nuova lista di espressioni applicando l'assorbimento e l'assorbimento negativo.

    Consulta https://en.wikipedia.org/wiki/Absorption_law

    Assorbimento::

        A & (A | B) = A, A | (A & B) = A

    Assorbimento negativo::

        A & (~A | B) = A & B, A | (~A & B) = A | B
    """
    nuove_espressioni = []

    for espressione in argomenti:
        if isinstance(espressione, tuple) and len(espressione) == 3:
            operatore, sinistra, destra = espressione

            # Assorbimento
            if operatore == '&' and isinstance(destra, tuple) and destra[0] == '|' and destra[1] == sinistra:
                nuove_espressioni.append(sinistra)
            elif operatore == '|' and isinstance(destra, tuple) and destra[0] == '&' and destra[1] == sinistra:
                nuove_espressioni.append(sinistra)

            # Assorbimento negativo
            elif operatore == '&' and isinstance(destra, tuple) and destra[0] == '|' and isinstance(destra[1], tuple) and destra[1][0] == '~' and destra[1][1] == sinistra:
                nuove_espressioni.append((operatore, sinistra, destra[2]))
            elif operatore == '|' and isinstance(destra, tuple) and destra[0] == '&' and isinstance(destra[1], tuple) and destra[1][0] == '~' and destra[1][1] == sinistra:
                nuove_espressioni.append((operatore, sinistra, destra[2]))

            else:
                nuove_espressioni.append(espressione)
        else:
            nuove_espressioni.append(espressione)

    return nuove_espressioni

def piu_o_punto(pezzi):
    """
    Restituisci un ""+"" se non è già presente, altrimenti restituisci un "".""
    """
    if "+" not in pezzi:
        return "+"
    else:
        return "."

import subprocess

def esegui_comando(comandi, argomenti, cwd=None, verbose=False, nascondi_stderr=False, env=None):
    """
    Esegui il comando specificato.
    """
    comando_completo = [comandi] + argomenti
    if verbose:
        print(f"Esecuzione del comando: {' '.join(comando_completo)}")

    stderr = subprocess.DEVNULL if nascondi_stderr else subprocess.PIPE

    try:
        risultato = subprocess.run(
            comando_completo,
            cwd=cwd,
            env=env,
            stdout=subprocess.PIPE,
            stderr=stderr,
            text=True
        )
        if verbose:
            print(f"Output del comando: {risultato.stdout}")
            if risultato.stderr:
                print(f"Errori del comando: {risultato.stderr}")

        return risultato.returncode, risultato.stdout, risultato.stderr
    except Exception as errore:
        if verbose:
            print(f"Errore durante l'esecuzione del comando: {errore}")
        return -1, None, str(errore)

def valida_gerarchia(self, oggetti_validati=True, controlla_digests=True, mostra_warning=False):
    """
    Valida la gerarchia di archiviazione.

    Restituisce:
        numero_oggetti - numero di oggetti verificati
        oggetti_validi - numero di oggetti verificati che sono risultati validi
    """
    numero_oggetti = 0
    oggetti_validi = 0

    for oggetto in self.gerarchia:
        numero_oggetti += 1
        if oggetti_validati:
            if oggetto.valido():
                oggetti_validi += 1
            elif mostra_warning:
                print(f"Attenzione: Oggetto {oggetto.id} non valido.")

        if controlla_digests:
            if not oggetto.verifica_digest():
                if mostra_warning:
                    print(f"Attenzione: Digest non valido per l'oggetto {oggetto.id}.")

    return numero_oggetti, oggetti_validi

