def gestori_protocollo(cls, versione_protocollo=None):
    """
    Restituisce un dizionario dei gestori di protocollo Bolt disponibili,
    indicizzati per tuple di versione. Se viene fornita una versione di protocollo
    esplicita, il dizionario conterrà zero o un elemento, a seconda che quella
    versione sia supportata o meno. Se non viene fornita alcuna versione di protocollo,
    verranno restituite tutte le versioni disponibili.

    :param versione_protocollo: tupla che identifica una specifica versione
        del protocollo (ad esempio, (3, 5)) oppure None
    :return: dizionario che associa una tupla di versione alla classe del gestore
        per tutte le versioni di protocollo rilevanti e supportate
    :raise TypeError: se la versione del protocollo non è passata come una tupla
    """
    gestori_disponibili = {
        (3, 5): cls.GestoreProtocolloV3_5,
        (4, 0): cls.GestoreProtocolloV4_0,
        (4, 1): cls.GestoreProtocolloV4_1,
    }

    if versione_protocollo is not None:
        if not isinstance(versione_protocollo, tuple):
            raise TypeError("La versione del protocollo deve essere una tupla.")
        if versione_protocollo in gestori_disponibili:
            return {versione_protocollo: gestori_disponibili[versione_protocollo]}
        else:
            return {}
    else:
        return gestori_disponibili

def da_valori_grezzi(cls, valori):
    """
    Crea un oggetto Bookmarks da una lista di valori stringa grezzi dei segnalibri.

    Non dovresti aver bisogno di utilizzare questo metodo a meno che tu non voglia
    deserializzare i segnalibri.

    :param valori: Valori stringa ASCII (segnalibri grezzi)
    :type valori: Iterable[str]
    """
    segnalibri = []
    for valore in valori:
        if isinstance(valore, str):
            segnalibro = cls._crea_segnalibro(valore)
            segnalibri.append(segnalibro)
        else:
            raise ValueError("I valori devono essere stringhe ASCII.")
    return cls(segnalibri)

def lista_di_nomi_file(directory_settaggi, opzioni_specifiche):
    """
    Crea un nuovo tipo complesso IniType
    """
    import os
    from configparser import ConfigParser

    class IniType:
        def __init__(self, percorso_file):
            self.parser = ConfigParser()
            self.parser.read(percorso_file)

        def ottieni_valore(self, sezione, chiave):
            return self.parser.get(sezione, chiave)

        def imposta_valore(self, sezione, chiave, valore):
            if not self.parser.has_section(sezione):
                self.parser.add_section(sezione)
            self.parser.set(sezione, chiave, valore)

        def salva_file(self, percorso_file):
            with open(percorso_file, 'w') as file_config:
                self.parser.write(file_config)

    lista_file = []
    for percorso, _, files in os.walk(directory_settaggi):
        for file in files:
            if file.endswith('.ini'):
                lista_file.append(os.path.join(percorso, file))

    return lista_file, IniType

def valida_deprecazione_argomenti(self, argomenti_linea_comando, dizionario_argomenti):
    """
    Valida e stampa gli argomenti deprecati.

    :param argomenti_linea_comando: il dizionario degli argomenti dalla CLI
    :param dizionario_argomenti: il dizionario degli argomenti dai file
    """
    argomenti_deprecati = set(argomenti_linea_comando.keys()) - set(dizionario_argomenti.keys())

    if argomenti_deprecati:
        print("Attenzione: i seguenti argomenti sono deprecati:")
        for argomento in argomenti_deprecati:
            print(f"- {argomento}")
    else:
        print("Nessun argomento deprecato trovato.")
